#include <vector>
#include <algorithm>

long long solve(std::vector<long long> prices, std::vector<long long> strategy, long long k) {
    long long n = prices.size();
    long long max_profit = 0;

    // Calculate the original profit
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }
    max_profit = original_profit;

    // Try to modify each possible subarray of length k
    for (int i = 0; i <= n - k; ++i) {
        long long modified_profit = original_profit;
        // Change the first k/2 elements to 0 (hold)
        for (int j = 0; j < k / 2; ++j) {
            int idx = i + j;
            modified_profit -= strategy[idx] * prices[idx];
            modified_profit += 0 * prices[idx];
        }
        // Change the last k/2 elements to 1 (sell)
        for (int j = 0; j < k / 2; ++j) {
            int idx = i + k / 2 + j;
            modified_profit -= strategy[idx] * prices[idx];
            modified_profit += 1 * prices[idx];
        }
        max_profit = std::max(max_profit, modified_profit);
    }

    return max_profit;
}
